// src/components/Profile.js
import React, { useState, useEffect, useRef } from "react";
import { FaUserCircle, FaTimes } from "react-icons/fa";

export default function Profile({ user, onLogout }) {
  const [open, setOpen] = useState(false);
  const sidebarRef = useRef();

  // lock body scroll while sidebar open
  useEffect(() => {
    if (open) {
      document.body.style.overflow = "hidden";
    } else {
      document.body.style.overflow = "";
    }
    return () => {
      document.body.style.overflow = "";
    };
  }, [open]);

  // close on Esc
  useEffect(() => {
    const onKey = (e) => {
      if (e.key === "Escape") setOpen(false);
    };
    window.addEventListener("keydown", onKey);
    return () => window.removeEventListener("keydown", onKey);
  }, []);

  // click outside to close (if needed)
  useEffect(() => {
    const handleClickOutside = (e) => {
      if (open && sidebarRef.current && !sidebarRef.current.contains(e.target)) {
        setOpen(false);
      }
    };
    document.addEventListener("mousedown", handleClickOutside);
    return () => document.removeEventListener("mousedown", handleClickOutside);
  }, [open]);

  const doLogout = () => {
    setOpen(false);
    if (typeof onLogout === "function") onLogout();
  };

  return (
    <>
      {/* small icon in header */}
      <div className="profile-wrapper" title="Open profile">
        <FaUserCircle
          className="profile-icon"
          size={36}
          onClick={() => setOpen(true)}
          aria-label="Open profile"
        />
      </div>

      {/* overlay */}
      <div
        className={`profile-overlay ${open ? "visible" : ""}`}
        style={{ pointerEvents: open ? "auto" : "none" }}
      />

      {/* sidebar */}
      <aside
        ref={sidebarRef}
        className={`profile-sidebar ${open ? "open" : ""}`}
        aria-hidden={!open}
      >
        <button className="profile-close" onClick={() => setOpen(false)} aria-label="Close">
          <FaTimes />
        </button>

        <div className="profile-box">
          <FaUserCircle className="profile-avatar" size={92} />
          <h3 className="profile-name">{user?.name || "User"}</h3>
          <p className="profile-email">{user?.email || "email@example.com"}</p>
        </div>

        <div className="profile-actions">
          <button className="logout-btn" onClick={doLogout}>
            Logout
          </button>
        </div>
      </aside>
    </>
  );
}
